head.script:
scwin.isRetrieveTree = false;
scwin.EXPEND_FG = 0;
scwin.preRow = 0;
scwin.viewMode = "S";
scwin.createRow = 0;
scwin.saveBranchCd = "";
scwin.dupChkOilStatNo = "";
scwin.isDupchk = false;
scwin.savePatternCd = "";
scwin.oilOilStatNo = "";
scwin.strCurDate = "";
scwin.hid_tvIndex = "1";
scwin.txt_frchNo = "X";
scwin.saveOilStatCd = "";

scwin.onpageload = function() {
    scwin.oilOilStatNo = $c.data.getParameter() != null && $c.data.getParameter()["oilStatNo"] != null ? $c.data.getParameter()["oilStatNo"] : "";
    scwin.strCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");

    lc_useYn.setValue("9");
    scwin.f_retrieveOilStatInfoTree();
    scwin.f_ContentsDisable();

    if (scwin.oilOilStatNo != "") {
        ed_oilStatNo.setValue(scwin.oilOilStatNo);
        scwin.f_Retrieve();
    }
};

scwin.f_retrieveOilStatInfoTree = async function() {
    scwin.isRetrieveTree = false;

    dma_oilStatInfoTreeCon.set("useYn", lc_useYn.getValue());
    dma_oilStatInfoTreeCon.set("qryConKnd", "ALL");

    ds_oilStatInfoTree.removeAll();
    await $c.sbm.execute(sbm_retrieveOilStatInfoList);
};

scwin.f_Retrieve = async function() {
    if (!(await $c.gus.cfValidate([ed_oilStatNo]))) {
        return;
    }
    let oilStatNo = ed_oilStatNo.getValue();
    let foundRow = scwin.f_NameValueRow(ds_oilStatInfoTree, "oilOilStatNo", oilStatNo);
    if (foundRow >= 0) {
        if (ds_oilStatInfoTree.getRowPosition() == foundRow) {
            if (scwin.viewMode == "U" || scwin.viewMode == "C") {
                let chk = await $c.win.confirm("현재 작업중 입니다. 취소 하시겠습니까?");
                if (!chk) {
                    return;
                }
            }

            if (scwin.viewMode == "C" && ds_oilStatInfoTree.getRowStatus(scwin.createRow) == "C") {
                ds_oilStatInfoTree.removeRow(scwin.createRow);
            }

            let curPos = ds_oilStatInfoTree.getRowPosition();
            // TODO: sub_title.innerText equivalent
            scwin.f_getOilStatInfo(curPos);
            scwin.f_RetrieveOilStatInfo(curPos);
        } else {
            scwin.preRow = -1;
            ds_oilStatInfoTree.setRowPosition(foundRow);
        }
        $c.gus.cfDisableBtn([b_Cancel2, b_Save2]);
        $c.gus.cfEnableObjects([b_Create2, b_Update2]);
    }
};

scwin.f_RetrieveOilStatInfo = async function(row) {
    dma_oilStatInfoCon.set("oilOilStatNo", ds_oilStatInfoTree.getCellData(row, "oilOilStatNo"));
    await $c.sbm.execute(sbm_retrieveOilStatContentsList);
};

scwin.f_Clear = async function() {
    let curPos = ds_oilStatInfoTree.getRowPosition();
    let oilStatNo = ds_oilStatInfoTree.getCellData(curPos, "oilOilStatNo");
    let oilStatNm = ds_oilStatInfoTree.getCellData(curPos, "oilStatNm");
    let curLevel = parseInt(ds_oilStatInfoTree.getCellData(curPos, "lvl"), 10);

    if (curLevel > 2) {
        await $c.gus.cfAlertMsg("지점 밑으로는 추가 할 수 없습니다.");
        return false;
    }
    let chk = await $c.win.confirm(oilStatNm + "의 하위 점소를 새로 등록 하시겠습니까?");
    if (!chk) {
        return;
    }

    let totalRow = ds_oilStatInfoTree.getRowCount();
    if ((curPos == totalRow - 1) || (curPos == 0)) {
        ds_oilStatInfoTree.insertRow(totalRow);
        let newIdx = ds_oilStatInfoTree.getRowCount() - 1;
        ds_oilStatInfoTree.setCellData(newIdx, "lvl", curLevel + 1);
        ds_oilStatInfoTree.setCellData(newIdx, "oilStatNm", curLevel == 0 ? "신규지사" : "신규지점");
        ds_oilStatInfoTree.setCellData(newIdx, "upperOilStrPlcNo", oilStatNo);
        tv_oilStatInfoTree.setNodePosition(newIdx);
    } else {
        ds_oilStatInfoTree.insertRow(curPos + 1);
        let newPos = curPos + 1;
        ds_oilStatInfoTree.setCellData(newPos, "lvl", curLevel + 1);
        ds_oilStatInfoTree.setCellData(newPos, "oilStatNm", curLevel == 0 ? "신규지사" : "신규지점");
        ds_oilStatInfoTree.setCellData(newPos, "upperOilStrPlcNo", oilStatNo);
    }

    scwin.createRow = ds_oilStatInfoTree.getRowPosition();

    scwin.viewMode = "C";
    $c.gus.cfInitObjects(tbl_content);
    chb_useYn.setValue("1");
    ed_opnOfcDt.setValue(scwin.strCurDate);
    ed_upperOilStrPlcNo.setValue(oilStatNo);
    txt_upperOilStrPlcNm.setValue(oilStatNm);
    scwin.f_ContentsEnable();
    txt_oilStatNo.setFocus();

    ds_oilPch.removeAll();

    ed_oilStatNo.setValue("");
    txt_oilStatNm.setValue("");

    if (curLevel == 0) {
        scwin.savePatternCd = "S";
    } else if (curLevel == 1) {
        scwin.savePatternCd = "J";
    } else if (curLevel == 2) {
        scwin.savePatternCd = "O";
    } else {
        await $c.gus.cfAlertMsg("주유소 구분 코드  에러입니다.");
        return false;
    }
    lc_oilStatLvlClsCd.setValue(scwin.savePatternCd);
    lc_bilgKndCd.setValue("M");
    $c.gus.cfDisableBtn([b_Create2, b_Update2]);
    $c.gus.cfEnableObjects([b_Cancel2, b_Save2]);
};

scwin.f_Update = async function() {
    let curPos = ds_oilStatInfoTree.getRowPosition();
    if (ds_oilStatInfoTree.getCellData(curPos, "oilOilStatNo") == "AAA") {
        await $c.gus.cfAlertMsg("전체는 수정 할 수 없습니다.");
        return;
    }
    scwin.viewMode = "U";
    scwin.f_ContentsEnable();
    $c.gus.cfDisableBtn([b_Create2, b_Update2]);
    $c.gus.cfEnableObjects([b_Cancel2, b_Save2]);
};

scwin.f_Cancel = async function() {
    let row = ds_oilStatInfoTree.getRowPosition();
    if (scwin.viewMode == "U") {
        if (scwin.isRetrieveTree) {
            let chk = await $c.win.confirm("현재 작업중 입니다. 취소 하시겠습니까?");
            if (!chk) {
                return;
            }
            scwin.f_getOilStatInfo(row);
            scwin.f_RetrieveOilStatInfo(row);
            scwin.viewMode = "S";
        }
        scwin.f_ContentsDisable();
    } else if (scwin.viewMode == "C") {
        scwin.preRow = -1;
        ds_oilStatInfoTree.setRowPosition(0);
    }
    $c.gus.cfDisableBtn([b_Cancel2, b_Save2]);
    $c.gus.cfEnableObjects([b_Create2, b_Update2]);
};

scwin.f_chkOilStatNoDup = async function() {
    if (!(await $c.gus.cfValidate([txt_oilStatNo]))) {
        return;
    }
    scwin.isDupchk = false;
    scwin.dupChkOilStatNo = txt_oilStatNo.getValue();
    await $c.sbm.execute(sbm_retrieveOilStatInfoListByDupChk);
};

scwin.f_Save = async function() {
    if (!(await $c.gus.cfValidate([txt_oilStatNo, txt_oilStatNm, ed_upperOilStrPlcNo, lc_oilStatLvlClsCd, lc_homeClsCd, lc_oilSelfClsCd, chb_spotsaleYn, ed_clntNo, ed_bilgAcctDeptCd,
        ed_stockAcctDeptCd, ed_opnOfcDt, txt_picNm, txt_telNo, chb_useYn, lc_oilTskClsCd, txt_telNo, lc_clntClsCd, txt_frchNoSh, ed_repClntNo]))) {
        return;
    }

    scwin.saveOilStatCd = txt_oilStatNo.getValue();

    if (!scwin.f_setOilStatInfo()) {
        return;
    }

    let oilStatNo = dma_oilStatInfoBySave.get("oilOilStatNo");

    for (let i = 0; i < ds_oilPch.getRowCount(); i++) {
        if (ds_oilPch.getRowStatus(i) == "C") {
            ds_oilPch.setCellData(i, "oilOilStatNo", oilStatNo);
        }
    }

    if (scwin.viewMode == "U") {
        await $c.sbm.execute(sbm_updateOilStatInfo);
    } else if (scwin.viewMode == "C") {
        if (!scwin.isDupchk || txt_oilStatNo.getValue() != scwin.dupChkOilStatNo) {
            await $c.gus.cfAlertMsg("중복체크를 하셔야 합니다.");
            return;
        }
        await $c.sbm.execute(sbm_createOilStatInfo);
    }
};

scwin.f_ContentsDisable = function() {
    $c.gus.cfEnableObj(txt_oilStatNo, false);
    $c.gus.cfEnableObj(txt_oilStatNm, false);
    $c.gus.cfEnableObj(btn_oilStatNoDup, false);
    $c.gus.cfEnableObj(ed_upperOilStrPlcNo, false);
    $c.gus.cfEnableObj(txt_upperOilStrPlcNm, false);
    // TODO: btn_upperOilStrPlcNo is part of udc_upperOilStrPlc
    $c.gus.cfEnableObj(lc_oilStatLvlClsCd, false);
    $c.gus.cfEnableObj(lc_homeClsCd, false);
    $c.gus.cfEnableObj(lc_oilSelfClsCd, false);
    $c.gus.cfEnableObj(chb_spotsaleYn, false);
    $c.gus.cfEnableObj(ed_clntNo, false);
    $c.gus.cfEnableObj(txt_clntNm, false);
    // TODO: btn_clntNo is part of udc_clnt
    $c.gus.cfEnableObj(ed_repClntNo, false);
    $c.gus.cfEnableObj(txt_repClntNm, false);
    // TODO: btn_repClntNo is part of udc_repClnt
    $c.gus.cfEnableObj(ed_bilgAcctDeptCd, false);
    $c.gus.cfEnableObj(txt_bilgAcctDeptNm, false);
    // TODO: btn_bilgAcctDeptCd is part of udc_bilgAcctDept
    $c.gus.cfEnableObj(ed_stockAcctDeptCd, false);
    $c.gus.cfEnableObj(txt_stockAcctDeptNm, false);
    // TODO: btn_stockAcctDeptCd is part of udc_stockAcctDept
    $c.gus.cfEnableObj(ed_opnOfcDt, false);
    $c.gus.cfEnableObj(ed_closOfcDt, false);
    $c.gus.cfEnableObj(txt_picNm, false);
    $c.gus.cfEnableObj(txt_telNo, false);
    $c.gus.cfEnableObj(chb_useYn, false);
    $c.gus.cfEnableObj(lc_oilTskClsCd, false);
    $c.gus.cfEnableObj(txt_rmk, false);
    $c.gus.cfEnableObj(chb_dsaleYn, false);
    $c.gus.cfEnableObj(lc_clntClsCd, false);
    $c.gus.cfEnableObj(txt_frchNoSh, false);
    $c.gus.cfEnableObj(lc_bilgKndCd, false);

    // TODO: btn_addRow1, btn_deleteRow1, btn_cancelRow1 are part of udc_bottomGrdBtn

    gr_oilPch.setReadOnly("grid", true);
};

scwin.f_ContentsEnable = function() {
    if (scwin.viewMode == "C") {
        $c.gus.cfEnableObj(txt_oilStatNo, true);
        $c.gus.cfEnableObj(btn_oilStatNoDup, true);
    }
    if (scwin.viewMode == "U") {
        $c.gus.cfEnableObj(ed_upperOilStrPlcNo, true);
        $c.gus.cfEnableObj(txt_upperOilStrPlcNm, true);
        // TODO: btn_upperOilStrPlcNo is part of udc_upperOilStrPlc
        $c.gus.cfEnableObj(lc_oilStatLvlClsCd, true);
    }
    $c.gus.cfEnableObj(txt_oilStatNm, true);
    $c.gus.cfEnableObj(lc_homeClsCd, true);
    $c.gus.cfEnableObj(lc_oilSelfClsCd, true);
    $c.gus.cfEnableObj(chb_spotsaleYn, true);
    $c.gus.cfEnableObj(ed_clntNo, true);
    $c.gus.cfEnableObj(txt_clntNm, true);
    // TODO: btn_clntNo is part of udc_clnt
    $c.gus.cfEnableObj(ed_repClntNo, true);
    $c.gus.cfEnableObj(txt_repClntNm, true);
    // TODO: btn_repClntNo is part of udc_repClnt
    $c.gus.cfEnableObj(ed_bilgAcctDeptCd, true);
    $c.gus.cfEnableObj(txt_bilgAcctDeptNm, true);
    // TODO: btn_bilgAcctDeptCd is part of udc_bilgAcctDept
    $c.gus.cfEnableObj(ed_stockAcctDeptCd, true);
    $c.gus.cfEnableObj(txt_stockAcctDeptNm, true);
    // TODO: btn_stockAcctDeptCd is part of udc_stockAcctDept
    $c.gus.cfEnableObj(ed_opnOfcDt, true);
    $c.gus.cfEnableObj(ed_closOfcDt, true);
    $c.gus.cfEnableObj(txt_picNm, true);
    $c.gus.cfEnableObj(txt_telNo, true);
    $c.gus.cfEnableObj(chb_useYn, true);
    $c.gus.cfEnableObj(lc_oilTskClsCd, true);
    $c.gus.cfEnableObj(txt_rmk, true);
    $c.gus.cfEnableObj(chb_dsaleYn, true);
    $c.gus.cfEnableObj(lc_clntClsCd, true);
    $c.gus.cfEnableObj(txt_frchNoSh, true);
    $c.gus.cfEnableObj(lc_bilgKndCd, true);

    // TODO: btn_addRow1, btn_deleteRow1, btn_cancelRow1 are part of udc_bottomGrdBtn

    gr_oilPch.setReadOnly("grid", false);
};

scwin.f_openCommonPopUp = function(disGubun, pCode, pName, pClose, pAllSearch) {
    let rtnList = [];

    switch (disGubun) {
        case 1:
            rtnList = $c.gus.cfCommonPopUp('retrieveAcctDeptCdInfo', pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
            $c.gus.cfSetReturnValue(rtnList, ed_bilgAcctDeptCd, txt_bilgAcctDeptNm);
            break;

        case 2:
            rtnList = $c.gus.cfCommonPopUp('retrieveAcctDeptCdInfo', pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
            $c.gus.cfSetReturnValue(rtnList, ed_stockAcctDeptCd, txt_stockAcctDeptNm);
            break;

        case 3:
            rtnList = $c.gus.cfCommonPopUp('retrieveClntList', pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
            $c.gus.cfSetReturnValue(rtnList, ed_clntNo, txt_clntNm);
            break;

        case 4:
            rtnList = $c.gus.cfCommonPopUp('retrieveFmsOilStationInfo', pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
            $c.gus.cfSetReturnValue(rtnList, ed_oilStatNo, txt_oilStaNm);
            break;

        case 5:
            rtnList = $c.gus.cfCommonPopUp('retrieveFmsOilStationInfo', pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
            $c.gus.cfSetReturnValue(rtnList, ed_upperOilStrPlcNo, txt_upperOilStrPlcNm);
            break;

        case 6:
            rtnList = $c.gus.cfCommonPopUp('retrieveAcctDeptCdInfo', pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
            $c.gus.cfSetReturnValue(rtnList, ed_pcostAcctDeptCd, txt_pcostAcctDeptNm);
            break;

        case 7:
            rtnList = $c.gus.cfCommonPopUp('retrieveClntList', pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
            $c.gus.cfSetReturnValue(rtnList, ed_repClntNo, txt_repClntNm);
            break;

        default:
            break;
    }
};

scwin.f_chkOpenCommonPopUp = function(inObj, pairObj, disGubun, isCode) {
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }

    $c.gus.cfClearPairObj(pairObj);

    let pVal = $c.gus.cfGetValue(inObj);

    if (isCode == null || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    } else {
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

scwin.f_getOilStatInfo = function(row) {
    scwin.f_ContentsDisable();
    txt_oilStatNo.setValue(ds_oilStatInfoTree.getCellData(row, "oilOilStatNo"));
    txt_oilStatNm.setValue(ds_oilStatInfoTree.getCellData(row, "oilStatNm"));
    ed_oilStatNo.setValue(ds_oilStatInfoTree.getCellData(row, "oilOilStatNo"));
    txt_oilStatNm.setValue(ds_oilStatInfoTree.getCellData(row, "oilStatNm"));
    ed_upperOilStrPlcNo.setValue(ds_oilStatInfoTree.getCellData(row, "upperOilStrPlcNo"));
    txt_upperOilStrPlcNm.setValue(ds_oilStatInfoTree.getCellData(row, "upperOilStrPlcNm"));
    lc_oilStatLvlClsCd.setValue(ds_oilStatInfoTree.getCellData(row, "oilStatLvlClsCd"));
    lc_homeClsCd.setValue(ds_oilStatInfoTree.getCellData(row, "homeClsCd"));
    lc_oilSelfClsCd.setValue(ds_oilStatInfoTree.getCellData(row, "oilSelfClsCd"));
    chb_spotsaleYn.setValue(ds_oilStatInfoTree.getCellData(row, "spotsaleYn") == "1" ? "1" : "0");
    ed_clntNo.setValue(ds_oilStatInfoTree.getCellData(row, "clntNo"));
    txt_clntNm.setValue(ds_oilStatInfoTree.getCellData(row, "clntNm"));
    ed_repClntNo.setValue(ds_oilStatInfoTree.getCellData(row, "repClntNo"));
    txt_repClntNm.setValue(ds_oilStatInfoTree.getCellData(row, "repClntNm"));
    ed_bilgAcctDeptCd.setValue(ds_oilStatInfoTree.getCellData(row, "bilgAcctDeptCd"));
    txt_bilgAcctDeptNm.setValue(ds_oilStatInfoTree.getCellData(row, "bilgAcctDeptNm"));
    ed_stockAcctDeptCd.setValue(ds_oilStatInfoTree.getCellData(row, "stockAcctDeptCd"));
    txt_stockAcctDeptNm.setValue(ds_oilStatInfoTree.getCellData(row, "stockAcctDeptNm"));
    ed_opnOfcDt.setValue(ds_oilStatInfoTree.getCellData(row, "opnOfcDt"));
    ed_closOfcDt.setValue(ds_oilStatInfoTree.getCellData(row, "closOfcDt"));
    txt_picNm.setValue(ds_oilStatInfoTree.getCellData(row, "picNm"));
    txt_telNo.setValue(ds_oilStatInfoTree.getCellData(row, "telNo"));
    chb_useYn.setValue(ds_oilStatInfoTree.getCellData(row, "useYn") == "1" ? "1" : "0");
    lc_oilTskClsCd.setValue(ds_oilStatInfoTree.getCellData(row, "oilTskClsCd"));
    txt_rmk.setValue(ds_oilStatInfoTree.getCellData(row, "rmk"));
    chb_dsaleYn.setValue(ds_oilStatInfoTree.getCellData(row, "dsaleYn"));
    lc_clntClsCd.setValue(ds_oilStatInfoTree.getCellData(row, "clntClsCd"));
    scwin.txt_frchNo = ds_oilStatInfoTree.getCellData(row, "frchNo");
    txt_frchNoSh.setValue(ds_oilStatInfoTree.getCellData(row, "frchNoSh"));
    lc_bilgKndCd.setValue(ds_oilStatInfoTree.getCellData(row, "bilgKndCd"));
};

scwin.f_setOilStatInfo = async function() {
    let curPos = ds_oilStatInfoTree.getRowPosition();
    let upperOilStrPlcNo = ed_upperOilStrPlcNo.getValue();
    let upperRow = scwin.f_NameValueRow(ds_oilStatInfoTree, "oilOilStatNo", upperOilStrPlcNo);
    let upperLevel = 0;
    if (upperRow >= 0) {
        upperLevel = parseInt(ds_oilStatInfoTree.getCellData(upperRow, "lvl"), 10);
    }
    if (upperLevel == 0) {
        scwin.savePatternCd = "S";
    } else if (upperLevel == 1) {
        scwin.savePatternCd = "J";
    } else if (upperLevel == 2) {
        scwin.savePatternCd = "O";
    } else {
        await $c.gus.cfAlertMsg("지점 구분 코드 에러입니다.");
        return false;
    }

    dma_oilStatInfoBySave.set("oilOilStatNo", txt_oilStatNo.getValue());
    dma_oilStatInfoBySave.set("oilStatNm", txt_oilStatNm.getValue());
    dma_oilStatInfoBySave.set("upperOilStrPlcNo", ed_upperOilStrPlcNo.getValue());
    dma_oilStatInfoBySave.set("upperOilStrPlcNm", txt_upperOilStrPlcNm.getValue());
    dma_oilStatInfoBySave.set("oilStatLvlClsCd", scwin.savePatternCd);
    dma_oilStatInfoBySave.set("homeClsCd", lc_homeClsCd.getValue());
    dma_oilStatInfoBySave.set("oilSelfClsCd", lc_oilSelfClsCd.getValue());
    dma_oilStatInfoBySave.set("spotsaleYn", chb_spotsaleYn.getValue() == "1" ? 1 : 0);
    dma_oilStatInfoBySave.set("clntNo", ed_clntNo.getValue());
    dma_oilStatInfoBySave.set("clntNm", txt_clntNm.getValue());
    dma_oilStatInfoBySave.set("repClntNo", ed_repClntNo.getValue());
    dma_oilStatInfoBySave.set("repClntNm", txt_repClntNm.getValue());
    dma_oilStatInfoBySave.set("bilgAcctDeptCd", ed_bilgAcctDeptCd.getValue());
    dma_oilStatInfoBySave.set("bilgAcctDeptNm", txt_bilgAcctDeptNm.getValue());
    dma_oilStatInfoBySave.set("stockAcctDeptCd", ed_stockAcctDeptCd.getValue());
    dma_oilStatInfoBySave.set("stockAcctDeptNm", txt_stockAcctDeptNm.getValue());
    dma_oilStatInfoBySave.set("opnOfcDt", ed_opnOfcDt.getValue());
    dma_oilStatInfoBySave.set("closOfcDt", ed_closOfcDt.getValue());
    dma_oilStatInfoBySave.set("picNm", txt_picNm.getValue());
    dma_oilStatInfoBySave.set("telNo", txt_telNo.getValue());
    dma_oilStatInfoBySave.set("useYn", chb_useYn.getValue() == "1" ? 1 : 0);
    dma_oilStatInfoBySave.set("oilTskClsCd", lc_oilTskClsCd.getValue());
    dma_oilStatInfoBySave.set("rmk", txt_rmk.getValue());
    dma_oilStatInfoBySave.set("dsaleYn", chb_dsaleYn.getValue() == "1" ? 1 : 0);
    dma_oilStatInfoBySave.set("pcostAcctDeptCd", "00276");
    dma_oilStatInfoBySave.set("pcostAcctDeptNm", "FMS운영");
    dma_oilStatInfoBySave.set("clntClsCd", lc_clntClsCd.getValue());
    dma_oilStatInfoBySave.set("frchNo", scwin.txt_frchNo);
    dma_oilStatInfoBySave.set("frchNoSh", txt_frchNoSh.getValue());
    dma_oilStatInfoBySave.set("bilgKndCd", lc_bilgKndCd.getValue());

    dma_oilStatInfoBySave.set("frchNo", "0");

    return true;
};

scwin.f_Expend = function() {
    if (scwin.EXPEND_FG == 1) {
        tv_oilStatInfoTree.expandLevel(0);
        scwin.EXPEND_FG = 0;
        btn_Expend.setValue("확장");
    } else {
        tv_oilStatInfoTree.expandLevel(3);
        scwin.EXPEND_FG = 1;
        btn_Expend.setValue("접기");
    }
};

scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects(tbl_search);
};

scwin.f_AddRow = function(dataSet) {
    $c.data.insertRow(dataSet);
};

scwin.f_DeleteRow = function(dataSet) {
    let rowPos = dataSet.getRowPosition();
    if (rowPos >= 0) {
        dataSet.removeRow(rowPos);
    }
};

scwin.f_NameValueRow = function(ds, colId, value) {
    for (let i = 0; i < ds.getRowCount(); i++) {
        if (ds.getCellData(i, colId) == value) {
            return i;
        }
    }
    return -1;
};

