scwin.sbm_retrieveOilStatInfoListByDupChk_submitdone = async function(e) {
    let foundRow = scwin.f_NameValueRow(ds_oilStatInfoTree, "oilOilStatNo", scwin.dupChkOilStatNo);
    if (foundRow >= 0) {
        await $c.gus.cfAlertMsg(scwin.dupChkOilStatNo + "는 이미 등록된 점소코드 입니다.");
        scwin.isDupchk = false;
        $c.gus.cfCopyDataSet(ds_chkOilStatNoDup, ds_oilStatInfoTree);
    } else {
        scwin.isDupchk = true;
        await $c.gus.cfAlertMsg(scwin.dupChkOilStatNo + "는 등록 가능 합니다.");
    }
};

